    def get(self, request):
        depth = (request.query_params.get('depth') or 'full').lower()
        snap = iproute.collect_kernel_snapshot()
        if depth == 'minimal':
            return Response(
                {
                    'link': snap.get('link'),
                    'address': snap.get('address'),
