"""
策略路由（ip rule）下发：维护内核 ip rule 列表与 PolicyRouteRule 意图的对账与下发。

实现策略：
- 不写 netplan（netplan routing-policy 只能挂在某个设备上，且字段受限）；
- 通过 `ip rule add/del` 直接操作内核；
- pemanager 仅清理优先级落在 PEMANAGER_OWNED_PRIO_RANGE 内的旧规则，避免误删系统/其他模块写入的规则；
- 提供 preview / apply / clear 三阶段；
- 同步过程中按 priority 升序 add（priority 缺省由内核分配）。
"""
from __future__ import annotations

import json
from typing import Any, Iterable, Literal

from django.conf import settings

from interfacemanage.services.netplan_writing import _run as _elevated_run

from routemanage.models import PolicyRouteRule

ApplyPhase = Literal['full', 'preview']

DEFAULT_OWNED_RANGE = (10000, 19999)


def _owned_range() -> tuple[int, int]:
    rng = getattr(settings, 'ROUTEMANAGE_IPRULE_OWNED_PRIO_RANGE', None)
    if not isinstance(rng, (list, tuple)) or len(rng) != 2:
        return DEFAULT_OWNED_RANGE
    try:
        lo, hi = int(rng[0]), int(rng[1])
        if lo > hi:
            lo, hi = hi, lo
        return lo, hi
    except (TypeError, ValueError):
        return DEFAULT_OWNED_RANGE


def _rule_to_args(rule: PolicyRouteRule) -> list[str]:
    """将 PolicyRouteRule 转换为 `ip [-4|-6] rule add <args>` 的尾部参数。"""
    args: list[str] = []
    if rule.priority is not None:
        args += ['priority', str(int(rule.priority))]
    if rule.invert:
        args += ['not']
    if (rule.from_cidr or '').strip():
        args += ['from', rule.from_cidr.strip()]
    else:
        args += ['from', 'all']
    if (rule.to_cidr or '').strip():
        args += ['to', rule.to_cidr.strip()]
    if (rule.iif or '').strip():
        args += ['iif', rule.iif.strip()]
    if (rule.oif or '').strip():
        args += ['oif', rule.oif.strip()]
    if (rule.fwmark or '').strip():
        args += ['fwmark', rule.fwmark.strip()]
    if (rule.tos or '').strip():
        args += ['tos', rule.tos.strip()]
    if rule.suppress_prefixlength is not None:
        args += ['suppress_prefixlength', str(int(rule.suppress_prefixlength))]

    if rule.action == PolicyRouteRule.Action.LOOKUP:
        args += ['lookup', str(int(rule.table_id))]
    elif rule.action == PolicyRouteRule.Action.NAT:
        args += ['nat', str(rule.nat_target)]
    elif rule.action == PolicyRouteRule.Action.BLACKHOLE:
        args += ['blackhole']
    elif rule.action == PolicyRouteRule.Action.UNREACHABLE:
        args += ['unreachable']
    elif rule.action == PolicyRouteRule.Action.PROHIBIT:
        args += ['prohibit']
    return args


def _family_flag(family: str) -> str:
    return '-6' if family == PolicyRouteRule.Family.INET6 else '-4'


def render_ip_rule_commands(rules: Iterable[PolicyRouteRule]) -> list[str]:
    out: list[str] = []
    for r in rules:
        if not r.enabled:
            continue
        argv = ['ip', _family_flag(r.family), 'rule', 'add', *_rule_to_args(r)]
        out.append(' '.join(argv))
    return out


def preview_policy_rules() -> dict[str, Any]:
    qs = PolicyRouteRule.objects.all().order_by('priority', 'id')
    cmds = render_ip_rule_commands(qs)
    lo, hi = _owned_range()
    return {
        'ok': True,
        'commands': cmds,
        'count': len(cmds),
        'owned_range': [lo, hi],
        'hint': (
            f'下发前会清理 priority 落在 [{lo}, {hi}] 范围内的旧规则；'
            '建议把 PE Manager 受控规则的 priority 设置在该范围内。'
        ),
    }


def _list_current_rules() -> list[dict[str, Any]]:
    out: list[dict[str, Any]] = []
    for family_flag in ('-4', '-6'):
        res = _elevated_run(['ip', '-json', family_flag, 'rule', 'show'])
        if not res.ok:
            continue
        try:
            data = json.loads(res.stdout or '[]')
        except json.JSONDecodeError:
            continue
        for row in data if isinstance(data, list) else []:
            if not isinstance(row, dict):
                continue
            row['_family_flag'] = family_flag
            out.append(row)
    return out


def _flush_owned_range() -> list[dict[str, Any]]:
    lo, hi = _owned_range()
    steps: list[dict[str, Any]] = []
    for row in _list_current_rules():
        prio = row.get('priority')
        try:
            prio_i = int(prio)
        except (TypeError, ValueError):
            continue
        if prio_i < lo or prio_i > hi:
            continue
        fam = row.get('_family_flag') or '-4'
        res = _elevated_run(['ip', fam, 'rule', 'del', 'priority', str(prio_i)], timeout_kind='apply')
        steps.append(
            {
                'step': 'rule del',
                'priority': prio_i,
                'family': fam,
                'ok': res.ok,
                'stderr': res.stderr,
            }
        )
    return steps


def apply_policy_rules(*, phase: ApplyPhase | str = 'full') -> dict[str, Any]:
    if not getattr(settings, 'ROUTEMANAGE_IPRULE_WRITE_ENABLED', False):
        return {'ok': False, 'error': '策略路由下发已关闭（settings.ROUTEMANAGE_IPRULE_WRITE_ENABLED）'}

    phase_l = (phase or 'full').lower()
    if phase_l == 'preview':
        return preview_policy_rules()

    qs = PolicyRouteRule.objects.all().order_by('priority', 'id')
    steps: list[dict[str, Any]] = []

    flush_steps = _flush_owned_range()
    steps.extend(flush_steps)

    add_count = 0
    failed: list[dict[str, Any]] = []
    for r in qs:
        if not r.enabled:
            continue
        argv = ['ip', _family_flag(r.family), 'rule', 'add', *_rule_to_args(r)]
        res = _elevated_run(argv, timeout_kind='apply')
        ok = res.ok
        steps.append(
            {
                'step': 'rule add',
                'argv': argv,
                'rule_id': str(r.id),
                'priority': r.priority,
                'ok': ok,
                'stderr': res.stderr,
            }
        )
        if ok:
            add_count += 1
        else:
            failed.append({'rule_id': str(r.id), 'stderr': res.stderr})

    return {
        'ok': not failed,
        'phase': phase_l,
        'added': add_count,
        'flushed': len([s for s in flush_steps if s.get('ok')]),
        'failed': failed,
        'steps': steps,
    }

"""
WireGuard 接口路由的「单独下发」。

为何独立：
- WG 接口的 netplan 规格里包含 keys.private，不应被 routemanage 的路由片段重复写入；
- 因此 WG 相关的 DesiredRouteConfig 不进入 99-pemanager-routes.yaml，而是通过 `ip route` 直接下发到内核；
- 持久化由 interfacemanage 的 WG 模块（99-pemanager-wireguard.yaml）+ 本模块在 networkd-dispatcher routable.d 中
  托管的 `pemanager-wg-routes.sh` 协同完成（脚本会在 wg 接口 up 后重放 ip route）。
"""
from __future__ import annotations

import os
from typing import Any, Iterable

from django.conf import settings

from interfacemanage.models import DesiredTunnelConfig
from interfacemanage.services.netplan_writing import _run as _elevated_run

from routemanage.models import DesiredRouteConfig

DEFAULT_WG_SCRIPT_PATH = '/etc/networkd-dispatcher/routable.d/91-pemanager-wg-routes.sh'


def _wg_ifnames() -> set[str]:
    return set(
        DesiredTunnelConfig.objects.filter(
            kind=DesiredTunnelConfig.Kind.WIREGUARD
        ).values_list('ifname', flat=True)
    )


def wireguard_route_intents() -> list[DesiredRouteConfig]:
    """筛选出与 WG 接口绑定的路由意图。"""
    wgs = _wg_ifnames()
    if not wgs:
        return []
    return list(
        DesiredRouteConfig.objects.filter(interface_name__in=wgs).order_by(
            'interface_name', 'dest_cidr', 'id'
        )
    )


def non_wireguard_route_intents() -> list[DesiredRouteConfig]:
    """所有非 WG 接口的路由意图（走 netplan 持久化）。"""
    wgs = _wg_ifnames()
    qs = DesiredRouteConfig.objects.all().order_by('interface_name', 'dest_cidr', 'id')
    if not wgs:
        return list(qs)
    return [r for r in qs if (r.interface_name or '').strip() not in wgs]


def _route_to_argv(rec: DesiredRouteConfig) -> list[str] | None:
    ifn = (rec.interface_name or '').strip()
    dst = (rec.dest_cidr or '').strip()
    if not ifn or not dst:
        return None
    argv = ['ip']
    if ':' in dst:
        argv.append('-6')
    elif dst.lower() == 'default':
        pass
    else:
        argv.append('-4')
    argv += ['route', 'replace', dst]
    if rec.gateway:
        argv += ['via', str(rec.gateway)]
    argv += ['dev', ifn]
    if rec.on_link:
        argv += ['onlink']
    if rec.metric is not None:
        argv += ['metric', str(int(rec.metric))]
    if rec.route_table is not None:
        argv += ['table', str(int(rec.route_table))]
    return argv


def render_wg_route_commands(rules: Iterable[DesiredRouteConfig]) -> list[str]:
    out: list[str] = []
    for r in rules:
        argv = _route_to_argv(r)
        if argv is None:
            continue
        out.append(' '.join(argv))
    return out


def render_wg_routes_script() -> str:
    rules = wireguard_route_intents()
    lines = [
        '#!/bin/sh',
        '# Managed by PE Manager — WireGuard route reapply on interface up.',
        '# Triggered by networkd-dispatcher (routable.d).',
        'set -u',
        'iface="${1:-}"',
        ': "${iface:=$IFACE}"',
        '',
    ]
    wgs = _wg_ifnames()
    for ifn in sorted(wgs):
        rules_for = [r for r in rules if (r.interface_name or '').strip() == ifn]
        if not rules_for:
            continue
        lines.append(f'if [ "$iface" = "{ifn}" ]; then')
        for r in rules_for:
            argv = _route_to_argv(r)
            if argv is None:
                continue
            lines.append('  ' + ' '.join(argv) + ' 2>/dev/null || true')
        lines.append('fi')
        lines.append('')
    return '\n'.join(lines) + '\n'


def preview_wg_routes() -> dict[str, Any]:
    rules = wireguard_route_intents()
    return {
        'ok': True,
        'count': len(rules),
        'commands': render_wg_route_commands(rules),
        'script_path': str(getattr(settings, 'ROUTEMANAGE_WG_ROUTES_SCRIPT_PATH', DEFAULT_WG_SCRIPT_PATH)),
        'script': render_wg_routes_script(),
    }


def _write_script_file(path: str, body: str) -> None:
    os.makedirs(os.path.dirname(path) or '/etc', exist_ok=True)
    with open(path, 'w', encoding='utf-8') as f:
        f.write(body)
    try:
        os.chmod(path, 0o755)
    except OSError:
        pass


def apply_wg_routes(*, write_script: bool = True) -> dict[str, Any]:
    """逐条 `ip route replace` 下发；可选写入 networkd-dispatcher 持久化脚本。"""
    if not getattr(settings, 'ROUTEMANAGE_IPROUTE_WRITE_ENABLED', False):
        return {'ok': False, 'error': 'WG 路由下发已关闭（settings.ROUTEMANAGE_IPROUTE_WRITE_ENABLED）'}

    rules = wireguard_route_intents()
    steps: list[dict[str, Any]] = []
    ok_count = 0
    failed: list[dict[str, Any]] = []
    for r in rules:
        argv = _route_to_argv(r)
        if argv is None:
            continue
        res = _elevated_run(argv, timeout_kind='apply')
        steps.append(
            {
                'step': 'route replace',
                'argv': argv,
                'rule_id': str(r.id),
                'ifname': r.interface_name,
                'ok': res.ok,
                'stderr': res.stderr,
            }
        )
        if res.ok:
            ok_count += 1
        else:
            failed.append({'rule_id': str(r.id), 'stderr': res.stderr})

    script_step: dict[str, Any] | None = None
    if write_script:
        path = str(getattr(settings, 'ROUTEMANAGE_WG_ROUTES_SCRIPT_PATH', DEFAULT_WG_SCRIPT_PATH))
        body = render_wg_routes_script()
        try:
            _write_script_file(path, body)
            script_step = {'step': 'write persistence script', 'path': path, 'ok': True, 'bytes': len(body)}
        except OSError as exc:
            script_step = {'step': 'write persistence script', 'path': path, 'ok': False, 'stderr': str(exc)}
        steps.append(script_step)

    return {
        'ok': not failed and (script_step is None or script_step.get('ok', True)),
        'applied': ok_count,
        'failed': failed,
        'steps': steps,
        'script_written': bool(script_step and script_step.get('ok')),
    }

