"""客户作用域工具：把"当前用户能看到哪些客户/接口名"集中起来，便于各 viewset 复用。"""
from __future__ import annotations

from typing import Iterable

from resourcemanage.models import IPAddressEntry, ResourceCustomer


def is_admin(user) -> bool:
    return bool(user and user.is_authenticated and getattr(user, 'is_admin_role', False))


def is_operator(user) -> bool:
    return bool(user and user.is_authenticated and getattr(user, 'is_operator_role', False))


def scope_customer(user) -> ResourceCustomer | None:
    """返回该用户绑定的客户；管理员/运维返回 None（表示无作用域限制）。"""
    if not (user and user.is_authenticated):
        return None
    if getattr(user, 'is_admin_role', False) or getattr(user, 'is_operator_role', False):
        return None
    cust = getattr(user, 'customer', None)
    return cust if cust else None


def scope_interface_codes(user) -> set[str] | None:
    """返回该用户能访问的接口标识集合；None 表示无限制（admin/operator）。

    客户能访问的接口 = 该客户在 IPAddressEntry 中所有非空的 `interface_code` 的去重集合，
    并叠加：BandwidthAllocation 中该客户的 `interface_code`、QoSPolicy 中绑定该客户的 `interface_name`。
    """
    cust = scope_customer(user)
    if cust is None and (is_admin(user) or is_operator(user)):
        return None
    if cust is None:
        # 未绑定客户的非 admin 用户：视为没有任何接口
        return set()

    codes: set[str] = set()
    # 1) IP 表
    for ic in IPAddressEntry.objects.filter(customer=cust).exclude(interface_code='').values_list(
        'interface_code', flat=True
    ):
        if ic:
            codes.add(ic.strip())

    # 2) 带宽分配
    try:
        from resourcemanage.models import BandwidthAllocation

        for ic in BandwidthAllocation.objects.filter(customer=cust).exclude(interface_code='').values_list(
            'interface_code', flat=True
        ):
            if ic:
                codes.add(ic.strip())
    except Exception:  # noqa: BLE001
        pass

    # 3) QoS 策略
    try:
        from qosmanage.models import QoSPolicy

        for nm in QoSPolicy.objects.filter(customer=cust).exclude(interface_name='').values_list(
            'interface_name', flat=True
        ):
            if nm:
                codes.add(nm.strip())
    except Exception:  # noqa: BLE001
        pass

    return codes


def filter_by_interface_codes(qs, field: str, codes: Iterable[str] | None):
    """通用：把 queryset 按"接口字段属于该集合"过滤；codes=None 表示无限制。"""
    if codes is None:
        return qs
    return qs.filter(**{f'{field}__in': list(codes)})

"""自定义认证：
- `APITokenAuthentication`：识别 Authorization: Bearer pem_<prefix>.<secret> 或 X-API-Key 头。
- JWT 由 `rest_framework_simplejwt.authentication.JWTAuthentication` 直接承担（在 settings 中先放它）。

注意：simplejwt 的 JWTAuthentication 也读 `Authorization: Bearer ...`，但 JWT 不以 `pem_` 开头；
本类放在 DRF DEFAULT_AUTHENTICATION_CLASSES 中 JWTAuthentication 之后，看到非 JWT 的 `pem_*` 才接管。
"""
from __future__ import annotations

from django.utils import timezone
from rest_framework import authentication, exceptions

from accountmanage.models import APIToken


def _client_ip(request) -> str | None:
    xff = (request.META.get('HTTP_X_FORWARDED_FOR') or '').strip()
    if xff:
        return xff.split(',')[0].strip()
    return request.META.get('REMOTE_ADDR') or None


class APITokenAuthentication(authentication.BaseAuthentication):
    keyword = 'Bearer'

    def authenticate(self, request):
        token_str = self._extract_token(request)
        if not token_str:
            return None
        if not token_str.startswith('pem_'):
            return None  # 让别的认证器接管（JWT 等）

        try:
            prefix, secret = token_str.split('.', 1)
        except ValueError:
            raise exceptions.AuthenticationFailed('API Token 格式应为 prefix.secret')

        try:
            tok = APIToken.objects.select_related('user').get(prefix=prefix)
        except APIToken.DoesNotExist:
            raise exceptions.AuthenticationFailed('API Token 无效')

        if tok.revoked:
            raise exceptions.AuthenticationFailed('API Token 已吊销')
        if tok.is_expired:
            raise exceptions.AuthenticationFailed('API Token 已过期')
        if not tok.verify_secret(secret):
            raise exceptions.AuthenticationFailed('API Token 密钥不匹配')
        if not tok.user.is_active:
            raise exceptions.AuthenticationFailed('用户已禁用')

        try:
            tok.mark_used(_client_ip(request))
        except Exception:  # noqa: BLE001
            pass

        # 把令牌挂回 request 便于审计 / 后续判断 scope
        request._api_token = tok
        return (tok.user, tok)

    @staticmethod
    def _extract_token(request) -> str | None:
        auth = request.META.get('HTTP_AUTHORIZATION', '') or ''
        if auth:
            parts = auth.split()
            if len(parts) == 2 and parts[0].lower() == 'bearer':
                return parts[1]
        xkey = request.META.get('HTTP_X_API_KEY')
        if xkey:
            return xkey.strip()
        return None

"""权限类：
- `IsAdmin`：只允许 admin / superuser。
- `IsOperator`：admin + operator。
- `IsAdminOrScopedReadOnly`：admin 全开；其他认证用户只允许只读（GET/HEAD/OPTIONS）。
- `ReadOnlyForCustomer`：客户角色禁止写，其它角色读写交由后续权限/视图层决定。
"""
from __future__ import annotations

from rest_framework.permissions import SAFE_METHODS, BasePermission

from accountmanage.services import scope as scope_svc


class IsAdmin(BasePermission):
    message = '需要管理员权限'

    def has_permission(self, request, view):
        return scope_svc.is_admin(request.user)


class IsOperator(BasePermission):
    message = '需要运维或管理员权限'

    def has_permission(self, request, view):
        return scope_svc.is_operator(request.user)


class IsAdminOrScopedReadOnly(BasePermission):
    """admin 全权；其他认证用户只读。客户用户由 viewset 的 get_queryset 自行作用域过滤。"""

    message = '权限不足'

    def has_permission(self, request, view):
        u = request.user
        if not (u and u.is_authenticated):
            return False
        if scope_svc.is_admin(u):
            return True
        return request.method in SAFE_METHODS


class ReadOnlyForCustomer(BasePermission):
    """客户角色禁止写；admin/operator 不受限。"""

    message = '客户账号仅可只读'

    def has_permission(self, request, view):
        u = request.user
        if not (u and u.is_authenticated):
            return False
        if scope_svc.is_admin(u) or scope_svc.is_operator(u):
            return True
        return request.method in SAFE_METHODS

