# ============================================================
# IP 批量操作
# ============================================================

# 单次批量录入上限，防止滥用导致大事务/UI 卡死
_BULK_IP_CREATE_MAX = 1024
# 其他批量动作（分配/释放/回收）上限
_BULK_IP_ACTION_MAX = 512


def _expand_addresses(
    *,
    addresses: list[str] | None,
    start: str | None,
    end: str | None,
) -> list[str]:
    """把 addresses + (start,end) 展开为去重、有序的 IP 字符串列表。"""
    seen: set[str] = set()
    out: list[str] = []

    def _add(ip_str: str) -> None:
        try:
            ip_obj = ipaddress.ip_address(ip_str)
        except ValueError as e:
            raise ValidationError(f'非法 IP {ip_str}: {e}') from e
        s = str(ip_obj)
        if s not in seen:
            seen.add(s)
            out.append(s)

    if start and end:
        try:
            a = ipaddress.ip_address(start)
            b = ipaddress.ip_address(end)
        except ValueError as e:
            raise ValidationError(f'非法起止 IP: {e}') from e
        if a.version != b.version:
            raise ValidationError('起始与结束 IP 版本不一致')
        if int(b) < int(a):
            raise ValidationError('结束 IP 必须 ≥ 起始 IP')
        span = int(b) - int(a) + 1
        if span > _BULK_IP_CREATE_MAX:
            raise ValidationError(
                f'起止区间共 {span} 个地址，超过单次最大值 {_BULK_IP_CREATE_MAX}'
            )
        cls = ipaddress.IPv4Address if a.version == 4 else ipaddress.IPv6Address
        for i in range(int(a), int(b) + 1):
            _add(str(cls(i)))
    elif start or end:
        raise ValidationError('start 与 end 必须同时提供')

    for s in addresses or []:
        if not s:
            continue
        _add(str(s).strip())

    return out


def bulk_create_ips(
    *,
    addresses: list[str] | None = None,
    start: str | None = None,
    end: str | None = None,
    state: str = IPAddressEntry.State.AVAILABLE,
    subnet_label: str = '',
    actor: str = 'api',
) -> dict[str, Any]:
    """批量录入 IP：

    - 入参支持「起止区间 start~end」 或「显式 IP 列表 addresses」（可同时给出，合并去重）；
    - 已存在的地址按"skip"处理（不会修改其状态/绑定）；
    - 失败的地址会进入 errors，不会中断整体；
    - 仅允许初始状态为 available / reserved。
    """
    if state not in (
        IPAddressEntry.State.AVAILABLE,
        IPAddressEntry.State.RESERVED,
    ):
        raise ValidationError('批量录入仅允许初始状态为 available / reserved')

    items = _expand_addresses(addresses=addresses, start=start, end=end)
    if not items:
        raise ValidationError('未提供任何待录入 IP')
    if len(items) > _BULK_IP_CREATE_MAX:
        raise ValidationError(f'本次共 {len(items)} 条，超过单次最大值 {_BULK_IP_CREATE_MAX}')

    created: list[str] = []
    skipped: list[dict[str, str]] = []
    errors: list[dict[str, str]] = []

    correlation_id = _cid()

    for addr in items:
        try:
            with transaction.atomic():
                exists = IPAddressEntry.objects.filter(address=addr).first()
                if exists:
                    skipped.append({'address': addr, 'reason': f'已存在（{exists.get_state_display()}）'})
                    continue
                entry = IPAddressEntry(
                    address=addr,
                    state=state,
                    subnet_label=subnet_label or '',
                )
                entry.full_clean()
                entry._skip_outbound = True  # noqa: SLF001
                entry.save()
                created.append(addr)
        except Exception as e:  # noqa: BLE001
            errors.append({'address': addr, 'error': str(e)})

    audit.log_action(
        ResourceAllocationLog.Action.IP_UPDATE,
        f'批量录入 IP：成功 {len(created)} / 跳过 {len(skipped)} / 失败 {len(errors)}',
        detail={
            'created': created,
            'skipped': skipped,
            'errors': errors,
            'state': state,
            'subnet_label': subnet_label,
        },
        actor=actor,
        correlation_id=correlation_id,
    )
    return {
        'ok': not errors,
        'total': len(items),
        'created': created,
        'skipped': skipped,
        'errors': errors,
    }


def _bulk_action_dispatch(
    addresses: list[str],
    action_fn,
    *,
    action_label: str,
    actor: str,
    extra_log: dict[str, Any] | None = None,
) -> dict[str, Any]:
    """统一封装：对地址列表逐条执行 action_fn(address=...)，结果聚合。"""
    if not addresses:
        raise ValidationError('未提供任何待操作 IP')
    items = list({str(a).strip() for a in addresses if a})
    if not items:
        raise ValidationError('未提供任何有效 IP')
    if len(items) > _BULK_IP_ACTION_MAX:
        raise ValidationError(
            f'本次共 {len(items)} 条，超过单次最大值 {_BULK_IP_ACTION_MAX}'
        )

    succeeded: list[dict[str, Any]] = []
    failed: list[dict[str, str]] = []

    for addr in sorted(items):
        try:
            with transaction.atomic():
                res = action_fn(addr)
            if isinstance(res, IPAddressEntry):
                succeeded.append({'address': addr, 'state': res.state})
            elif isinstance(res, dict):
                succeeded.append({'address': addr, **res})
            else:
                succeeded.append({'address': addr})
        except Exception as e:  # noqa: BLE001
            failed.append({'address': addr, 'error': str(e)})

    correlation_id = _cid()
    log_detail: dict[str, Any] = {
        'succeeded': succeeded,
        'failed': failed,
    }
    if extra_log:
        log_detail.update(extra_log)
    audit.log_action(
        ResourceAllocationLog.Action.IP_UPDATE,
        f'{action_label}：成功 {len(succeeded)} / 失败 {len(failed)}',
        detail=log_detail,
        actor=actor,
        correlation_id=correlation_id,
    )
    return {
        'ok': not failed,
        'total': len(items),
        'succeeded': succeeded,
        'failed': failed,
    }


def bulk_allocate_ips(
    *,
    addresses: list[str],
    customer: ResourceCustomer,
    interface_code: str = '',
    subnet_label: str = '',
    allow_from_reserved: bool = True,
    actor: str = 'api',
) -> dict[str, Any]:
    """批量分配 IP 给客户（每条独立事务，失败不影响其他）。"""
    if not customer:
        raise ValidationError('必须指定 customer')

    def _do(addr: str):
        return allocate_ip(
            address=addr,
            customer=customer,
            interface_code=interface_code or '',
            subnet_label=subnet_label or '',
            allow_from_reserved=allow_from_reserved,
            actor=actor,
        )

    return _bulk_action_dispatch(
        addresses,
        _do,
        action_label=f'批量分配 IP 给客户 {customer.code}',
        actor=actor,
        extra_log={
            'customer_code': customer.code,
            'interface_code': interface_code or '',
            'subnet_label': subnet_label or '',
        },
    )


def bulk_release_ips(
    *,
    addresses: list[str],
    actor: str = 'api',
) -> dict[str, Any]:
    """批量释放 IP（清空客户/接口绑定，删除关联路由意图）。"""

    def _do(addr: str):
        return release_ip(address=addr, actor=actor)

    return _bulk_action_dispatch(
        addresses,
        _do,
        action_label='批量释放 IP',
        actor=actor,
    )


def bulk_recycle_ips(
    *,
    addresses: list[str],
    reason: str = '',
    actor: str = 'api',
) -> dict[str, Any]:
    """批量回收 IP（标记为 recycled，不可再分配）。"""

    def _do(addr: str):
        return recycle_ip(address=addr, reason=reason or '', actor=actor)

    return _bulk_action_dispatch(
        addresses,
        _do,
        action_label='批量回收 IP',
        actor=actor,
        extra_log={'reason': reason or ''},
    )

@action(detail=False, methods=['post'], url_path='actions/bulk-create', permission_classes=[IsAuthenticated, IsAdmin])
def bulk_create(self, request):
    """批量录入：起止 start~end 与 addresses 二选一或并用，结果聚合返回。"""
    s = IPBulkCreateSerializer(data=request.data)
    s.is_valid(raise_exception=True)
    data = s.validated_data
    try:
        result = operations.bulk_create_ips(
            addresses=data.get('addresses') or [],
            start=str(data['start']) if data.get('start') else None,
            end=str(data['end']) if data.get('end') else None,
            state=data.get('state') or 'available',
            subnet_label=data.get('subnet_label') or '',
            actor=data.get('actor') or 'api',
        )
    except Exception as e:  # noqa: BLE001
        raise DRFValidationError(str(e)) from e
    return Response(result, status=status.HTTP_200_OK)

@action(detail=False, methods=['post'], url_path='actions/bulk-allocate', permission_classes=[IsAuthenticated, IsAdmin])
def bulk_allocate(self, request):
    """批量分配 IP 给客户；每条独立事务、失败不中断。"""
    s = IPBulkAllocateSerializer(data=request.data)
    s.is_valid(raise_exception=True)
    data = s.validated_data
    cust = ResourceCustomer.objects.filter(code=data['customer_code']).first()
    if not cust:
        raise DRFValidationError({'customer_code': '客户不存在'})
    try:
        result = operations.bulk_allocate_ips(
            addresses=[str(a) for a in data['addresses']],
            customer=cust,
            interface_code=data.get('interface_code') or '',
            subnet_label=data.get('subnet_label') or '',
            allow_from_reserved=data.get('allow_from_reserved', True),
            actor=data.get('actor') or 'api',
        )
    except Exception as e:  # noqa: BLE001
        raise DRFValidationError(str(e)) from e
    return Response(result, status=status.HTTP_200_OK)

@action(detail=False, methods=['post'], url_path='actions/bulk-release', permission_classes=[IsAuthenticated, IsAdmin])
def bulk_release(self, request):
    """批量释放（含删除关联路由意图）。"""
    s = IPBulkReleaseSerializer(data=request.data)
    s.is_valid(raise_exception=True)
    data = s.validated_data
    try:
        result = operations.bulk_release_ips(
            addresses=[str(a) for a in data['addresses']],
            actor=data.get('actor') or 'api',
        )
    except Exception as e:  # noqa: BLE001
