def _iface_exists(ifn: str) -> bool:
    """通过 `ip link show dev <ifn>` 检测出接口在系统中是否存在。"""
    if not ifn:
        return False
    res = _run(['ip', '-o', 'link', 'show', 'dev', ifn], timeout_kind='apply')
    return bool(res.ok)


def _iface_connected_nets(ifn: str, *, family: int) -> list[Any]:
    """读取出接口上指定族（4/6）的直连子网列表，用于判断 gateway 是否直连。"""
    import ipaddress as _ip

    flag = '-4' if family == 4 else '-6'
    res = _run(['ip', flag, '-o', 'addr', 'show', 'dev', ifn], timeout_kind='apply')
    nets: list[Any] = []
    if not res.ok:
        return nets
    for line in (res.stdout or '').splitlines():
        parts = line.split()
        for i, p in enumerate(parts):
            if p in ('inet', 'inet6') and i + 1 < len(parts):
                try:
                    nets.append(_ip.ip_interface(parts[i + 1]).network)
                except Exception:
                    continue
    return nets


def apply_desired_routes_immediate(ids: list[str] | set[str]) -> dict[str, Any]:
    """
    选择性下发：仅对给定 id 集合中的非 WG 路由意图用 `ip route replace` 直接下发到内核，
    不写入 netplan fragment、不执行 netplan generate / try，因此完全不影响其它接口与路由。

    增强：
    - 出接口不存在时直接给出明确错误（避免内核抛 misleading 的 "Nexthop has invalid gateway"）；
    - 透传 `on_link`；
    - 若 gateway 不落在 dev 的任一直连子网内且未勾选 on-link，
      自动追加 `onlink` 以兼容典型隧道场景，并在 steps 中显式标注 `auto_onlink: true`。

    持久化由后续的全量 `apply_desired_routes_netplan(phase='full')` 处理。
    """
    import ipaddress as _ip

    from routemanage.models import DesiredRouteConfig
    from interfacemanage.models import DesiredTunnelConfig

    id_set = {str(i) for i in (ids or [])}
    if not id_set:
        return {'ok': True, 'steps': [], 'message': '选中集合为空'}
    qs = list(DesiredRouteConfig.objects.filter(id__in=id_set).order_by('interface_name', 'dest_cidr', 'id'))
    wg_set = set(
        DesiredTunnelConfig.objects.filter(kind=DesiredTunnelConfig.Kind.WIREGUARD).values_list('ifname', flat=True)
    )
    steps: list[dict[str, Any]] = []
    applied: list[str] = []
    failed: list[dict[str, Any]] = []
    for r in qs:
        ifn = (r.interface_name or '').strip()
        if ifn in wg_set:
            steps.append({
                'step': 'skip',
                'id': str(r.id),
                'reason': f'接口 {ifn} 为 WireGuard，请通过「下发 WireGuard 路由」入口',
            })
            continue

        if ifn and not _iface_exists(ifn):
            msg = (
                f'出接口 dev {ifn} 在系统中不存在；'
                f'请先在「隧道接口配置」中创建并下发到系统，或修改该路由的出接口。'
            )
            steps.append({
                'step': 'precheck',
                'id': str(r.id),
                'ifname': ifn,
                'ok': False,
                'stderr': msg,
            })
            failed.append({'id': str(r.id), 'argv': [], 'stderr': msg})
            continue

        if (r.dest_cidr or '').strip().lower() == 'default':
            fam_num = 4
        else:
            try:
                fam_num = _ip.ip_network(r.dest_cidr, strict=False).version
            except Exception:
                fam_num = 4
        fam = '-4' if fam_num == 4 else '-6'

        # via + on-link 处理
        gw_str = str(r.gateway) if r.gateway else ''
        gw_via_parts: list[str] = []
        auto_onlink = False
        auto_onlink_reason = ''
        if gw_str:
            gw_via_parts += ['via', gw_str]
            needs_onlink = bool(r.on_link)
            try:
                gw_ip = _ip.ip_address(gw_str)
                connected = _iface_connected_nets(ifn, family=gw_ip.version) if ifn else []
                if not r.on_link and connected and not any(gw_ip in n for n in connected):
                    needs_onlink = True
                    auto_onlink = True
                    auto_onlink_reason = (
                        f'网关 {gw_str} 不在 dev {ifn} 的任一直连子网内；'
                        f'未启用 on-link 时内核会拒绝（Nexthop has invalid gateway）。'
                        f'已自动追加 onlink 进行本次即时下发；'
                        f'如需持久化请在路由意图中勾选 on-link 并执行「全量下发」。'
                    )
            except Exception:
                pass
            if needs_onlink:
                gw_via_parts += ['onlink']

        argv = ['ip', fam, 'route', 'replace', r.dest_cidr]
        argv += gw_via_parts
        if ifn:
            argv += ['dev', ifn]
        if r.metric is not None:
            argv += ['metric', str(int(r.metric))]
        if r.route_table is not None:
            argv += ['table', str(int(r.route_table))]
        res = _run(argv, timeout_kind='apply')
        step: dict[str, Any] = {
            'step': 'ip route replace',
            'id': str(r.id),
            'argv': argv,
            'ok': res.ok,
            'stderr': res.stderr,
        }
        if auto_onlink:
            step['auto_onlink'] = True
            step['auto_onlink_reason'] = auto_onlink_reason
        steps.append(step)
        if res.ok:
            applied.append(str(r.id))
        else:
            failed.append({'id': str(r.id), 'argv': argv, 'stderr': res.stderr})
    return {
        'ok': not failed,
        'applied': applied,
        'failed': failed,
        'steps': steps,
        'note': '本次仅对选中路由用 ip route replace 即时下发；如需持久化请执行全量下发',
    }

