def bulk_allocate_ips(
    *,
    addresses: list[str],
    customer: ResourceCustomer,
    interface_code: str = '',
    subnet_label: str = '',
    allow_from_reserved: bool = True,
    actor: str = 'api',
) -> dict[str, Any]:
