    if not customer:
        raise ValidationError('必须指定 customer')

    def _do(addr: str):
        return allocate_ip(
            address=addr,
            customer=customer,
            interface_code=interface_code or '',
            subnet_label=subnet_label or '',
            allow_from_reserved=allow_from_reserved,
            actor=actor,
        )

    return _bulk_action_dispatch(
        addresses,
        _do,
        action_label=f'批量分配 IP 给客户 {customer.code}',
        actor=actor,
        extra_log={
            'customer_code': customer.code,
            'interface_code': interface_code or '',
            'subnet_label': subnet_label or '',
